export const TOTAL_UNITS = CURRICULUM.length         // 30
export const DRILLS_PER_UNIT = 10
export const TOTAL_DRILLS = TOTAL_UNITS * DRILLS_PER_UNIT  // 300

export function getUnit(id: number): Unit | undefined {
  return CURRICULUM.find(u => u.id === id)
}

export function getDrill(unitId: number, drillIndex: number): Drill | undefined {
  return getUnit(unitId)?.drills[drillIndex]
}

export function getCycleUnits(cycle: 1 | 2 | 3): Unit[] {
  return CURRICULUM.filter(u => u.cycle === cycle)
}
